mapper.select:
SELECT COALESCE(SUM(value), 0)
FROM trend_data
WHERE project_id = #{projectId}
  AND source      = #{source}
  AND metric_type = #{metricType}
  AND data_date BETWEEN #{startDate} AND #{endDate}

SELECT COUNT(DISTINCT keyword)
FROM trend_data
WHERE project_id = #{projectId}
  AND data_date BETWEEN #{startDate} AND #{endDate}

SELECT
    keyword,
    SUM(CASE WHEN data_date BETWEEN #{currentStart} AND #{currentEnd}
             THEN value ELSE 0 END) AS currentVolume,
    SUM(CASE WHEN data_date BETWEEN #{prevStart}    AND #{prevEnd}
             THEN value ELSE 0 END) AS prevVolume
FROM trend_data
WHERE project_id = #{projectId}
  AND source = 'baidu_index'
  AND data_date BETWEEN #{prevStart} AND #{currentEnd}
GROUP BY keyword
ORDER BY currentVolume DESC
LIMIT #{limit}
